import React, { useState } from "react";
import "./App.css";

function App() {
  // List of card image paths (make sure filenames match exactly)
  const cardImages = [
    "/cards/1_bereshitA.png",
    "/cards/1B_bereshitB.png",
    "/cards/har_habayit_1a.png",
    "/cards/har_habayit_1b.png",
    "/cards/tzadik_card.png",
    "/cards/Sotah_47.png",
  ];

  const [currentCardIndex, setCurrentCardIndex] = useState(0);

  const handlePrevious = () => {
    setCurrentCardIndex((prevIndex) =>
      (prevIndex - 1 + cardImages.length) % cardImages.length
    );
  };

  const handleNext = () => {
    setCurrentCardIndex((prevIndex) =>
      (prevIndex + 1) % cardImages.length
    );
  };

  return (
    <div className="App" style={{ textAlign: "center", padding: "40px" }}>
      <h1>Parsha Card Viewer</h1>

      <img
        src={cardImages[currentCardIndex]}
        alt="Card"
        style={{
          width: "300px",
          height: "auto",
          border: "2px solid #333",
          borderRadius: "12px",
          boxShadow: "0 4px 10px rgba(0,0,0,0.2)",
          marginBottom: "20px",
        }}
      />

      <div>
        <button onClick={handlePrevious} style={buttonStyle}>Previous</button>
        <button onClick={handleNext} style={{ ...buttonStyle, marginLeft: "10px" }}>
          Next
        </button>
      </div>

      <p style={{ marginTop: "20px" }}>
        Showing card {currentCardIndex + 1} of {cardImages.length}
      </p>
    </div>
  );
}

// Optional button styling
const buttonStyle = {
  padding: "10px 20px",
  fontSize: "16px",
  borderRadius: "8px",
  border: "none",
  backgroundColor: "#007bff",
  color: "white",
  cursor: "pointer",
};

export default App;
